$root=require dirname(__DIR__).'/bootstrap/app.php';
use Dompdf\Dompdf;use Dompdf\Options;use Vigilancia\Database\Connection;use Vigilancia\Repositories\SecurityLogRepository;use Vigilancia\Repositories\SupervisionRepository;use Vigilancia\Services\AuthService;use Vigilancia\Services\SupervisionEvidenceService;use Vigilancia\Services\SupervisionService;use Vigilancia\Support\ClientInfo;use Vigilancia\Support\Config;use Vigilancia\Support\Session;
Session::start();$pdo=Connection::make(Config::database());$auth=new AuthService($pdo);$actor=$auth->current();$repo=new SupervisionRepository($pdo);$service=new SupervisionService($pdo,$repo,new SupervisionEvidenceService($root),new SecurityLogRepository($pdo));$s=$service->report($actor,(int)($_GET['id']??0));if($s['status']!=='completed'){http_response_code(409);exit('La supervisión aún no ha finalizado.');}$e=static fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');$photos='';foreach($s['evidence']as$file){$row=$repo->evidence((int)$file['id']);$path=$row?$root.'/'.$row['file_path']:'';if(is_file($path))$photos.='<img src="data:'.$row['mime_type'].';base64,'.base64_encode((string)file_get_contents($path)).'">';}$comments='';foreach($s['comments']as$c)$comments.='<p><strong>'.$e($c['author_name']).'</strong> · '.$e($c['created_at']).'<br>'.$e($c['comment']).'</p>';$points=implode(', ',array_map(static fn($p)=>$e($p['name']),$s['points']));$responsible=$s['responsible_absent']?'Ausente · '.$e($s['absence_reason']):$e($s['responsible_confirmation_name']);$html='<!doctype html><html lang="es"><head><meta charset="utf-8"><style>@page{margin:32px}body{font-family:DejaVu Sans,sans-serif;color:#0B1D3A;font-size:11px}header{padding:20px;background:#0B1D3A;color:#fff;border-radius:10px}h1{margin:0;font-size:24px}.folio{color:#486A92;font-weight:bold}.grid{display:table;width:100%;margin:18px 0}.grid div{display:table-cell;width:33%;padding:10px;background:#F5F7FA;border:2px solid white}.photos img{width:30%;height:145px;object-fit:cover;margin:1.5%;border-radius:8px}.sign{margin-top:20px;border-top:1px solid #486A92;padding-top:10px}.muted{color:#486A92}</style></head><body><header><h1>Sistema de Vigilancia</h1><p>Reporte de supervisión · Acceso seguro con código QR</p></header><h2>Supervisión <span class="folio">'.$e($s['folio']).'</span></h2><div class="grid"><div><strong>Cliente</strong><br>'.$e($s['client_name']).'</div><div><strong>Lugar</strong><br>'.$e($s['location_name']).'</div><div><strong>Puntos</strong><br>'.$points.'</div></div><p><strong>Supervisor:</strong> '.$e($s['supervisor_name']).'<br><strong>Inicio:</strong> '.$e($s['started_at']).'<br><strong>Finalización:</strong> '.$e($s['completed_at']).'</p><h3>Observaciones</h3><p>'.$e($s['observations']).'</p><h3>Evidencias</h3><div class="photos">'.($photos?:'<p class="muted">Sin evidencias fotográficas.</p>').'</div><h3>Confirmaciones</h3><p class="sign"><strong>Supervisor:</strong> '.$e($s['supervisor_confirmation_name']).' · '.$e($s['supervisor_confirmed_at']).'</p><p class="sign"><strong>Vigilante o responsable:</strong> '.$responsible.($s['responsible_confirmed_at']?' · '.$e($s['responsible_confirmed_at']):'').'</p><h3>Comentarios adicionales</h3>'.($comments?:'<p class="muted">Sin comentarios adicionales.</p>').'<p class="muted">Generado el '.gmdate('Y-m-d H:i:s').' UTC por '.$e($actor['full_name']).'. Documento auditable.</p></body></html>';$options=new Options();$options->set('isRemoteEnabled',false);$dompdf=new Dompdf($options);$dompdf->loadHtml($html,'UTF-8');$dompdf->setPaper('letter','portrait');$dompdf->render();(new SecurityLogRepository($pdo))->record((int)$actor['id'],'supervisions.pdf_generated',ClientInfo::ip(),ClientInfo::userAgent(),['supervision_id'=>$s['id'],'folio'=>$s['folio']]);$dompdf->stream($s['folio'].'.pdf',['Attachment'=>false]);
